const errors = [];

const inn = ($('Code in JavaScript').first().json.output.inn || "");
const kpp = ($('Code in JavaScript').first().json.output.kpp || "");
const loanAmount = ($('Code in JavaScript').first().json.output.loanAmount || "");
const loanTerm = ($('Code in JavaScript').first().json.output.loanTerm || "");

const requestDate = $('Code in JavaScript').first().json.output.requestDate;

if (!/^\d{10}$/.test(inn)) {
  errors.push("ИНН должен содержать 10 цифр");
}

if (kpp && !/^\d{9}$/.test(kpp)) {
  errors.push("КПП должен содержать 9 цифр");
}

if (loanAmount <= 0) {
  errors.push("Сумма кредита должна быть больше 0");
}

if (loanTerm < 1 || loanTerm > 120) {
  errors.push("Срок кредита должен быть от 1 до 120 месяцев");
}


// Разрешены только цифры
const textFields = { inn, kpp, loanTerm, loanAmount };
const fieldNames = { inn: "ИНН", kpp: "КПП", loanTerm: "Срок кредита", loanAmount: "Сумма кредита" };

for (const [fieldName, value] of Object.entries(textFields)) {
    if (value && !/^\d+$/.test(value)) {
        errors.push(`Поле "${fieldNames[fieldName]}" должно содержать только цифры`);
    }
}

const errorMessage = errors.join(", ");
const applicationId = $('Code in JavaScript').first().json.applicationId;
const tool = '02_Input_Validation';

return [{
  json: {
    applicationId,
    tool,
    output: {
    validationPassed: errors.length === 0,

    inn,
    kpp,
    loanAmount,
    loanTerm,
    requestDate,

    errors,
    errorMessage,
  }}
}];

