const results = [];

for (const item of $("Code in JavaScript2").all()) {

  const profile = item.json.output.company_profile || {};

  const findings = [];

  const status = profile.company_status;
  const director = profile.director;
  const address = profile.address;

  // ==========================================
  // ПРОВЕРКА РИСКОВ ПО СТАТУСУ КОМПАНИИ
  // ==========================================

  if (status === "LIQUIDATING") {
    findings.push("LIQUIDATING"); // Компания находится в процессе ликвидации
  }

  if (status === "LIQUIDATED") {
    findings.push("LIQUIDATED"); // Компания ликвидирована
  }

  if (status === "REORGANIZING") {
    findings.push("REORGANIZING"); // Компания находится в процессе реорганизации
  }

  // ==========================================
  // ПРОВЕРКА РИСКОВ ПО РЕЕСТРОВЫМ ПРИЗНАКАМ
  // ==========================================

  if (
    profile.mass_address === true ||
    profile.address_flag === "MASS_ADDRESS"
  ) {
    findings.push("MASS_ADDRESS"); // Адрес относится к массовым адресам регистрации
  }

  if (
    profile.mass_director === true ||
    profile.director_flag === "MASS_DIRECTOR"
  ) {
    findings.push("MASS_DIRECTOR"); // Руководитель является массовым директором
  }

  // ==========================================
  // ПРОВЕРКА ПОЛНОТЫ ИНФОРМАЦИИ
  // ==========================================

  const missingDirector =
    !director || director.trim() === "";

  const missingAddress =
    !address || address.trim() === "";

  if (missingDirector || missingAddress) {
    findings.push("INVALID_INFORMATION"); // Отсутствуют обязательные сведения о компании
  }

  // ==========================================
  // ПРОВЕРКА ЮРИДИЧЕСКИХ РИСКОВ
  // ==========================================

  if (profile.bankruptcy_indicator === true) {
    findings.push("BANKRUPTCY_INDICATOR"); // Выявлены признаки банкротства
  }

  if (profile.egrul_exclusion_risk === true) {
    findings.push("EGRUL_EXCLUSION_RISK"); // Есть риск исключения из ЕГРЮЛ
  }

  // ==========================================
  // ЕСЛИ НАРУШЕНИЯ НЕ ОБНАРУЖЕНЫ
  // ==========================================

  if (findings.length === 0) {
    findings.push("NO_COMPLIANCE_ISSUES_FOUND"); // Комплаенс-риски не выявлены
  }

  // ==========================================
  // РАСЧЕТ УРОВНЯ УВЕРЕННОСТИ В ОЦЕНКЕ
  // ==========================================

  let missingFields = 0;

  if (!status) {
    missingFields++;
  }

  if (!director || director.trim() === "") {
    missingFields++;
  }

  if (!address || address.trim() === "") {
    missingFields++;
  }

  let confidence;

  if (missingFields === 0) {
    confidence = "HIGH"; // Высокая уверенность: все ключевые данные присутствуют
  } else if (missingFields === 1) {
    confidence = "MEDIUM"; // Средняя уверенность: отсутствует одно ключевое поле
  } else {
    confidence = "LOW"; // Низкая уверенность: отсутствует несколько ключевых полей
  }

  // ==========================================
  // ФОРМИРОВАНИЕ РЕЗУЛЬТАТА
  // ==========================================
const applicationId = $('Code in JavaScript2').first().json.applicationId;
const tool = '06_Compliance_Assessment';

  results.push({
    json: {
      applicationId,
      tool,
      output: {
      compliance_assessment: {
        compliance_findings: findings,
        compliance_confidence: confidence
        }
      }
    }
  });

}

return results;

