const findings = [];

const revenue = Number($input.first().json.output.revenue || 0);
const profit = Number($input.first().json.output.net_profit || 0);
const assets = Number($input.first().json.output.assets || 0);
const liabilities = Number($input.first().json.output.liabilities || 0);

// ==========================================
// ПРОВЕРКА НАЛИЧИЯ ФИНАНСОВОЙ ОТЧЕТНОСТИ
// ==========================================

if (!$input.first().json.output.financial_data_found) {
  findings.push("NO_FINANCIAL_DATA");
  // Финансовые данные отсутствуют
}

// ==========================================
// ПРОВЕРКА НАЛИЧИЯ ВЫРУЧКИ
// ==========================================

if (revenue > 0) {
  findings.push("REVENUE_PRESENT");
  // Выручка больше нуля
}

// ==========================================
// ПРОВЕРКА ЧИСТОЙ ПРИБЫЛИ
// ==========================================

if (profit > 0) {
  findings.push("POSITIVE_NET_PROFIT");
  // Чистая прибыль больше нуля
}

if (profit < 0) {
  findings.push("NEGATIVE_NET_PROFIT");
  // Чистая прибыль меньше нуля
}

// ==========================================
// СРАВНЕНИЕ АКТИВОВ И ОБЯЗАТЕЛЬСТВ
// ==========================================

if (assets > liabilities && assets > 0) {
  findings.push("ASSETS_GREATER_THAN_LIABILITIES");
  // Активы превышают обязательства
}

if (liabilities > assets && liabilities > 0) {
  findings.push("LIABILITIES_GREATER_THAN_ASSETS");
  // Обязательства превышают активы
}

// ==========================================
// ОПРЕДЕЛЕНИЕ УРОВНЯ РИСКА
// ==========================================

let risk = "LOW";
// Не выявлены признаки для повышения уровня риска

if (
  findings.includes("NEGATIVE_NET_PROFIT") ||
  findings.includes("LIABILITIES_GREATER_THAN_ASSETS")
) {
  risk = "HIGH";
  // Выявлена отрицательная чистая прибыль
  // или обязательства превышают активы
}
else if (
  findings.includes("NO_FINANCIAL_DATA")
) {
  risk = "MEDIUM";
  // Финансовые данные отсутствуют
}

const applicationId = $input.first().json.applicationId;
const tool = '07_Financial_Assessment';

return [{
  json: {
      applicationId,
      tool,
      output: {
        financial_assessment: {
          financial_findings: findings,
          financial_risk_level: risk,
          revenue,
          net_profit: profit,
          assets,
          liabilities,
          reporting_year: $input.first().json.output.reporting_year
        }
      }
  }
}];

const item = $input.first().json.output;

let score = 0;
const riskFactors = [];

// ==========================================
// ПОЛУЧЕНИЕ РЕЗУЛЬТАТОВ ПРОВЕРОК
// ==========================================

const registration =
  $input.first().json.output.registration_assessment.registration_findings || [];

const compliance = $input.first().json.output.compliance_assessment.compliance_findings || [];

const reputation = $input.first().json.output.reputation_assessment.reputation_findings || [];

const financial = $input.first().json.output.financial_assessment.financial_findings
  || [];

const credit =
  $input.first().json.output.credit_assessment
    .credit_findings || [];

// ==========================================
// РЕГИСТРАЦИОННЫЕ ФАКТОРЫ
// ==========================================

if (registration.includes("LIQUIDATING")) {
  score += 100;
  riskFactors.push("LIQUIDATING");
  // Компания находится в процессе ликвидации
}

if (registration.includes("LIQUIDATED")) {
  score += 100;
  riskFactors.push("LIQUIDATED");
  // Компания ликвидирована
}

// ==========================================
// КОМПЛАЕНС-ФАКТОРЫ
// ==========================================

if (compliance.includes("MASS_ADDRESS")) {
  score += 20;
  riskFactors.push("MASS_ADDRESS");
  // Выявлен признак массового адреса
}

// ==========================================
// РЕПУТАЦИОННЫЕ ФАКТОРЫ
// ==========================================

if (
  reputation.includes("PUBLIC_LITIGATION_MENTIONED")
) {
  score += 15;
  riskFactors.push(
    "PUBLIC_LITIGATION_MENTIONED"
  );
  // Выявлен признак PUBLIC_LITIGATION_MENTIONED
}

// ==========================================
// ФИНАНСОВЫЕ ФАКТОРЫ
// ==========================================

if (
  financial.includes("NEGATIVE_NET_PROFIT")
) {
  score += 30;
  riskFactors.push(
    "NEGATIVE_NET_PROFIT"
  );
  // Чистая прибыль меньше нуля
}

if (
  financial.includes("POSITIVE_NET_PROFIT")
) {
  score -= 5;
  // Чистая прибыль больше нуля
}

// ==========================================
// КРЕДИТНЫЕ ФАКТОРЫ
// ==========================================

if (
  credit.includes("LOAN_EXCEEDS_REVENUE")
) {
  score += 40;
  riskFactors.push(
    "LOAN_EXCEEDS_REVENUE"
  );
  // Сумма займа превышает выручку
}

if (
  credit.includes("LOAN_TO_REVENUE_HIGH")
) {
  score += 30;
  riskFactors.push(
    "LOAN_TO_REVENUE_HIGH"
  );
  // Отношение суммы займа к выручке > 1
}

if (
  credit.includes("LOAN_TO_REVENUE_MODERATE")
) {
  score += 15;
  riskFactors.push(
    "LOAN_TO_REVENUE_MODERATE"
  );
  // Отношение суммы займа к выручке > 0.3 и ≤ 1
}

if (
  credit.includes("NO_PROFIT_SUPPORT")
) {
  score += 15;
  riskFactors.push(
    "NO_PROFIT_SUPPORT"
  );
  // Чистая прибыль отсутствует либо не больше нуля
}

if (
  credit.includes("LOAN_SUPPORTED_BY_PROFIT")
) {
  score -= 5;
  // Отношение суммы займа к чистой прибыли ≤ 2
}

// ==========================================
// РЕПУТАЦИОННЫЕ СОБЫТИЯ
// ==========================================

if (
  reputation.includes("FRAUD_ALLEGATION_FOUND")
) {
  score += 100;
  riskFactors.push(
    "FRAUD_ALLEGATION_FOUND"
  );
  // Выявлен признак FRAUD_ALLEGATION_FOUND
}

if (
  reputation.includes("REPUTATIONAL_SCANDAL_FOUND")
) {
  score += 100;
  riskFactors.push(
    "REPUTATIONAL_SCANDAL_FOUND"
  );
  // Выявлен признак REPUTATIONAL_SCANDAL_FOUND
}

// ==========================================
// НОРМАЛИЗАЦИЯ БАЛЛА РИСКА
// ==========================================

if (score < 0) {
  score = 0;
}

// ==========================================
// ОПРЕДЕЛЕНИЕ УРОВНЯ РИСКА
// ==========================================

let riskLevel = "LOW";
// Итоговый балл риска меньше 20

if (score >= 50) {
  riskLevel = "HIGH";
  // Итоговый балл риска 50 или выше
}
else if (score >= 20) {
  riskLevel = "MEDIUM";
  // Итоговый балл риска от 20 до 49 включительно
}

// ==========================================
// ФОРМИРОВАНИЕ РЕЗУЛЬТАТА
// ==========================================

const applicationId = $input.first().json.applicationId;
const tool = '08_Risk_Assessment';

return [{
  json: {
      applicationId,
      tool,
      output: {
        ...item,

          risk_assessment: {
            risk_score: score,
            risk_level: riskLevel,
            risk_factors: riskFactors
          }
    }
  }
}]
;

