for (const item of $input.all()) {

  const revenue =
    Number($input.first().json.output.revenue || 0);

  const profit =
    Number($input.first().json.output.net_profit || 0);

  const loanAmount =
    Number(
      $('Company Profile Builder')
        .first()
        .json
        .output
        .company_profile
        .requested_loan_amount || 0
    );

  const findings = [];

