    loan_to_profit = loanAmount / profit;
  }

  // ==========================================
  // АНАЛИЗ ОТНОШЕНИЯ ЗАЙМА К ВЫРУЧКЕ
  // ==========================================

  if (loan_to_revenue !== null) {

    if (loan_to_revenue <= 0.3) {
      findings.push("LOAN_TO_REVENUE_LOW");
      // Отношение суммы займа к выручке ≤ 0.3
    }

    else if (loan_to_revenue <= 1) {
      findings.push("LOAN_TO_REVENUE_MODERATE");
      // Отношение суммы займа к выручке > 0.3 и ≤ 1
    }

    else {
      findings.push("LOAN_TO_REVENUE_HIGH");
      // Отношение суммы займа к выручке > 1
    }

  } else {

    findings.push("REVENUE_DATA_MISSING");
    // Отсутствуют данные о выручке либо выручка не больше нуля

  }

