    'ACCUSED',
    'INVESTIGATED',
    'DEFENDANT',
    'CONVICTED'
  ]);

  const addFraudRisk =
    evidences.some(
      e => fraudRoles.has(e.company_role)
    );

  if (
    addFraudRisk &&
    !risks.includes('FRAUD_ALLEGATION_FOUND')
  ) {
    risks.push('FRAUD_ALLEGATION_FOUND');
  }
}


// INFORMATION INSUFFICIENCY

if (
  data.reputation_assessment?.information_sufficiency ===
  'INSUFFICIENT'
) {
  risks.push('INSUFFICIENT_PUBLIC_INFORMATION');
}


// remove duplicates again

const uniqueRisks = [...new Set(risks)];


// risk

const riskScore =
  data.risk_assessment?.risk_score ?? 0;

const riskLevel =
  data.risk_assessment?.risk_level || 'LOW';


// policy

const policyDecision =
  data.decision_explanation?.auto_decision ||
  'APPROVE';

const policyRulesTriggered =
  data.decision_explanation?.triggered_policy_rules ||
  [];


// SPECIAL RULE

const onlyOkvedMissing =
  uniqueRisks.length === 1 &&
  uniqueRisks[0] === 'OKVED_MISSING' &&
  data.reputation_assessment?.information_sufficiency ===
    'SUFFICIENT';


// decision

let decision = 'APPROVE';

if (policyDecision === 'DECLINE') {

  decision = 'DECLINE';

} else if (policyDecision === 'MANUAL_REVIEW') {

  decision = 'REVIEW';

} else if (onlyOkvedMissing) {

  decision = 'APPROVE';

} else {

  if (riskLevel === 'HIGH') {
    decision = 'DECLINE';
  }
  else if (riskLevel === 'MEDIUM') {
    decision = 'REVIEW';
  }
  else {
    decision = 'APPROVE';
  }

}

return [{
  json: {

    decision,

    overall_risk: riskLevel,

    risk_score: riskScore,

    policy_decision: policyDecision,

    policy_rules_triggered: policyRulesTriggered,

    strengths,

    risks: uniqueRisks


  }
}];

const findings = $input.first().json.findings || [];

const resultFindings = [];
const reputationFindings = [];

let totalEvidence = 0;

for (const item of findings) {

  const evidences = item.evidences || [];

  totalEvidence += evidences.length;

  let confidence = 'LOW';

  if (evidences.length >= 3) {
    confidence = 'HIGH';
  } else if (evidences.length >= 1) {
    confidence = 'MEDIUM';
  }

  resultFindings.push({
    reputation_finding: item.reputation_finding,

    confidence_finding: confidence,

    evidences: evidences.map(e => ({
      source: e.source ?? null,
      quote: e.quote ?? null,
      date: e.date ?? null,
      url: e.url ?? null,
      company_role: e.company_role ?? null,
      confidence: e.confidence ?? null
    }))
  });

  if (evidences.length > 0) {
    reputationFindings.push(item.reputation_finding);
  }
}

let reputationFindingsFinal = [...new Set(reputationFindings)];

if (reputationFindingsFinal.length === 0) {
  reputationFindingsFinal = ['NO_REPUTATION_DATA'];
}

let searchConfidence = 'LOW';

const foundSignals =
  reputationFindingsFinal.includes('NO_REPUTATION_DATA')
    ? 0
    : reputationFindingsFinal.length;

if (foundSignals >= 3) {
  searchConfidence = 'HIGH';
} else if (foundSignals >= 1) {
  searchConfidence = 'MEDIUM';
}

return [
  {
    json: {
      reputation_findings: reputationFindingsFinal,
      search_confidence: searchConfidence,
      information_sufficiency:
        totalEvidence > 0 ? 'SUFFICIENT' : 'INSUFFICIENT',
      findings: resultFindings
    }
  }
];
